def health_check():
    try:
        redis_client.ping()
        return jsonify({
            'status': 'healthy',
            'redis': 'connected'
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'redis': 'disconnected'
        }), 503

